from dataclasses import dataclass, field
from typing import Any
from enum import Enum


class FeedbackKind(Enum):
    SUCCESS = "success"
    TOOL_ERROR = "tool_error"
    VALIDATION_ERROR = "validation_error"
    TIMEOUT = "timeout"
    PERMISSION_DENIED = "permission_denied"


@dataclass
class Feedback:
    kind: FeedbackKind
    tool_name: str
    tool_use_id: str
    output: Any          # result payload on success
    error: str | None    # error message on failure
    duration_ms: float

    def to_tool_result_message(self) -> dict:
        """Format as an Anthropic tool_result content block."""
        if self.kind == FeedbackKind.SUCCESS:
            content = str(self.output)
        else:
            content = f"[{self.kind.value}] {self.error}"
        return {
            "type": "tool_result",
            "tool_use_id": self.tool_use_id,
            "content": content,
            "is_error": self.kind != FeedbackKind.SUCCESS,
        }


def classify_result(result: "ActionResult", tool_use_id: str) -> Feedback:
    if result.success:
        kind = FeedbackKind.SUCCESS
    elif "timeout" in (result.error or "").lower():
        kind = FeedbackKind.TIMEOUT
    elif "permission" in (result.error or "").lower():
        kind = FeedbackKind.PERMISSION_DENIED
    elif "invalid" in (result.error or "").lower():
        kind = FeedbackKind.VALIDATION_ERROR
    else:
        kind = FeedbackKind.TOOL_ERROR
    return Feedback(
        kind=kind,
        tool_name=result.action_name or "unknown",
        tool_use_id=tool_use_id,
        output=result.output,
        error=result.error,
        duration_ms=result.duration_ms,
    )

from collections import deque


@dataclass
class ObservationWindow:
    """Sliding window of recent observations kept in the agent's context."""
    max_turns: int = 20
    _turns: deque = field(default_factory=lambda: deque())

    def record(self, user_msg: dict, assistant_msg: dict) -> None:
        """Append a user+assistant turn pair; evict oldest if over limit."""
        self._turns.append((user_msg, assistant_msg))
        while len(self._turns) > self.max_turns:
            self._turns.popleft()

    def record_feedback(self, feedback: Feedback) -> None:
        """Append a tool-result user message to the latest turn.
        The Anthropic API requires tool results come as user-role messages.
        """
        tool_result_turn = {
            "role": "user",
            "content": [feedback.to_tool_result_message()],
        }
        # Tool results are appended as a separate turn (not part of prior pair)
        self._turns.append((tool_result_turn, None))
        while len(self._turns) > self.max_turns:
            self._turns.popleft()

    def to_messages(self) -> list[dict]:
        """Flatten window into an ordered message list for the API call."""
        messages = []
        for user_msg, assistant_msg in self._turns:
            messages.append(user_msg)
            if assistant_msg is not None:
                messages.append(assistant_msg)
        return messages

    @property
    def turn_count(self) -> int:
        return len(self._turns)
